// IATA → city name lookup for Hotellook (which expects city names, not codes).
const IATA_TO_CITY = {
  ATH: 'Athens', IST: 'Istanbul', BCN: 'Barcelona', LIS: 'Lisbon',
  LHR: 'London', CDG: 'Paris', FCO: 'Rome', MAD: 'Madrid', DXB: 'Dubai',
  AMS: 'Amsterdam', BUD: 'Budapest', VIE: 'Vienna', PRG: 'Prague',
  BER: 'Berlin', MUC: 'Munich', AYT: 'Antalya', PMI: 'Palma',
  MLA: 'Valletta', SKG: 'Thessaloniki', SOF: 'Sofia', ZAG: 'Zagreb',
  TIV: 'Tivat', SJJ: 'Sarajevo', SKP: 'Skopje', INI: 'Niš', BEG: 'Belgrade'
};

const body = $input.first().json.body || $input.first().json;
const from = String(body.from || '').toUpperCase();
const to = String(body.to || '').toUpperCase();
const depart = String(body.depart || '');
const ret = String(body.return || '');
const pax = parseInt(body.pax, 10) || 2;
const currency = String(body.currency || 'EUR').toUpperCase();
const nights = Math.max(1, Math.ceil((new Date(ret) - new Date(depart)) / 86400000));
const city = IATA_TO_CITY[to] || to;
const cacheKey = `${from}-${to}-${depart.replace(/-/g,'')}-${ret.replace(/-/g,'')}-${pax}`;

return [{ json: { from, to, depart, return: ret, pax, currency, nights, city, cacheKey } }];

// Cache hit — unpack and respond
const raw = $input.first().json.fields.result.stringValue;
const payload = JSON.parse(raw);
return [{ json: { ...payload, cache_hit: true } }];

const hotels = $input.first().json || [];
const input = $('Normalize Input').first().json;
return hotels.slice(0, 20).map((h) => ({
  json: {
    id: `ht_${h.hotelId}`,
    type: 'hotel',
    name: h.hotelName,
    stars: h.stars || null,
    rating: h.rating || null,
    location: (h.location && h.location.name) || null,
    distance_to_center_km: h.distance || null,
    price_per_night: h.priceFrom,
    price_total: h.priceFrom * input.nights,
    currency: 'EUR',
    affiliate_url: `https://search.hotellook.com/?destination=${encodeURIComponent((h.location && h.location.name) || input.city)}&checkIn=${input.depart}&checkOut=${input.return}&adults=${input.pax}&hotelId=${h.hotelId}&marker=${$env.TP_MARKER}`,
    source: 'hotellook'
  }
}));

// Aggregate, score, sort, build recommended pair
const flights = $('Flight Normalize').all().map(i => i.json);
const hotels = $('Hotel Normalize').all().map(i => i.json);
const input = $('Normalize Input').first().json;

const TIER1_CARRIERS = ['JU', 'LH', 'OS', 'TK', 'AF', 'BA', 'IB', 'AY', 'KL'];
const TIER2_CARRIERS = ['W6', 'FR', 'U2', 'PC', 'VY'];

let flightsScored = [];
if (flights.length) {
  const minFlightPrice = Math.min(...flights.map(f => f.price_total));
  flightsScored = flights.map(f => {
    const price_score = 50 * (minFlightPrice / f.price_total);
    const stops_score = 30 * (1 / (1 + (f.stops_outbound + f.stops_return)));
    let carrier_score = 10;
    if (TIER1_CARRIERS.includes(f.carrier)) carrier_score = 20;
    else if (TIER2_CARRIERS.includes(f.carrier)) carrier_score = 15;
    return { ...f, quality_score: Math.round(price_score + stops_score + carrier_score) };
  }).sort((a,b) => b.quality_score - a.quality_score).slice(0, 5);
}

let hotelsScored = [];
if (hotels.length) {
  const minHotelPrice = Math.min(...hotels.map(h => h.price_total));
  hotelsScored = hotels.map(h => {
    const price_score = 40 * (minHotelPrice / h.price_total);
    const rating_score = 40 * ((h.rating || 6) / 10);
    const stars_score = 20 * ((h.stars || 3) / 5);
    return { ...h, quality_score: Math.round(price_score + rating_score + stars_score) };
  }).sort((a,b) => b.quality_score - a.quality_score).slice(0, 5);
}

const rf = flightsScored[0];
const rh = hotelsScored[0];
const recommended = rf && rh ? {
  flight_id: rf.id,
  hotel_id: rh.id,
  total_price: rf.price_total + rh.price_total,
  combined_quality_score: Math.round((rf.quality_score + rh.quality_score) / 2),
  currency: 'EUR'
} : null;

const city = input.city;
const cityMeta = { name: city, sr: city };

return [{ json: {
  query: { from: input.from, to: input.to, depart: input.depart, return: input.return, pax: input.pax },
  city: cityMeta,
  nights: input.nights,
  flights: flightsScored,
  hotels: hotelsScored,
  recommended,
  summary: null,
  cache_hit: false
} }];

