// Extract summary or null on failure; merge with score-rank result
const stage5d = $('Quality Score & Rank').first().json;
let summary = null;
try {
  const r = $input.first().json;
  summary = (r && r.content && r.content[0] && r.content[0].text) ? String(r.content[0].text).trim() : null;
} catch (e) { summary = null; }
return [{ json: { ...stage5d, summary } }];

